import{_ as t,c as i,o as a,ak as o,an as n}from"./chunks/framework.CUmoI4gT.js";const m=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-116-0.md","filePath":"aireblock-releases/aireglu-v1-116-0.md","lastUpdated":1778063574000}'),s={name:"aireblock-releases/aireglu-v1-116-0.md"};function r(l,e,c,d,h,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+n+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.116.0<br><strong>Release Date:</strong> 21st April 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>AireForms Schema Auto-Import for Endpoints (GLU-2873)</li><li>Connect Endpoints to AI Assistants via MCP (GLU-2904)</li><li>Tenant-Wide Client Credential Connections for HTTP Requests (GLU-2998)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Unsaved Changes Warning in Endpoint Editor (GLU-2813)</li><li>Removed Minimum Items from Auto-Generated Schemas (GLU-2945)</li><li>Retry Support for Internal AireGlu Endpoint Calls (GLU-2967)</li><li>Metrics Table Refresh Button (GLU-2915)</li><li>Retry Visibility in Metrics (GLU-3007)</li><li>Narrowed Retry Conditions to Specific HTTP Exceptions (GLU-3024)</li><li>AI Tools Features Now Opt-In per Tenant (GLU-3087)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Reactivated Jobs No Longer Run Immediately (GLU-2955)</li><li>JSON Editor Overflow Fixed on JWT Headers (GLU-2900)</li><li>Config Assistant Error Fixed Following BFF Migration (GLU-2996)</li><li>Improved Error Message for Empty XML Schema on Save (GLU-3036)</li><li>Search No Longer Opens All Groups When Cleared (GLU-3016)</li></ul><h4 id="🔒-security-updates" tabindex="-1">🔒 Security Updates <a class="header-anchor" href="#🔒-security-updates" aria-label="Permalink to “🔒 Security Updates”">​</a></h4><ul><li>Various security updates and patches</li></ul><h3 id="⚠️-upgrade-notes" tabindex="-1">⚠️ Upgrade Notes <a class="header-anchor" href="#⚠️-upgrade-notes" aria-label="Permalink to “⚠️ Upgrade Notes”">​</a></h3><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p><strong>YAML Export Removed:</strong> Support for exporting endpoint definitions in YAML format has been removed in this release. If your workflows depend on YAML exports, please migrate to the JSON export format before upgrading.</p><p><strong>AI Tools Feature Gating:</strong> Tenants wishing to use these new AI features should contact Airelogic support.</p></div><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="aireforms-schema-auto-import-for-endpoints-glu-2873" tabindex="-1">AireForms Schema Auto-Import for Endpoints (GLU-2873) <a class="header-anchor" href="#aireforms-schema-auto-import-for-endpoints-glu-2873" aria-label="Permalink to “AireForms Schema Auto-Import for Endpoints (GLU-2873)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The endpoint input configuration now supports an &quot;AireForms&quot; input mode. When selected, users can choose a form key, version, and delivery channel, and AireGlu will automatically retrieve and populate the input schema from AireForms — keeping it in sync as the form evolves. The schema editor becomes read-only in this mode, and the configuration is preserved across sessions.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If you&#39;re integrating AireGlu with AireForms, you no longer need to manually copy and paste schemas into your endpoints. Simply select the form and version you want, and AireGlu will pull the correct schema in for you automatically — saving time and reducing the risk of errors when forms are updated.</p></div><h4 id="connect-endpoints-to-ai-assistants-via-mcp-glu-2904" tabindex="-1">Connect Endpoints to AI Assistants via MCP (GLU-2904) <a class="header-anchor" href="#connect-endpoints-to-ai-assistants-via-mcp-glu-2904" aria-label="Permalink to “Connect Endpoints to AI Assistants via MCP (GLU-2904)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireGlu now supports exposing endpoints as tools via the Model Context Protocol (MCP), allowing AI assistants such as Claude Desktop to discover and invoke your endpoints directly. This release includes MCP server configuration management, authentication via OAuth client credentials and AireIdentity, agent card definition support (per the A2A spec), and a runtime discovery layer so calling agents can resolve endpoint schemas dynamically. The GraphQL Nitro UI has also been restricted to non-production environments as part of this work.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now connect your AireGlu endpoints directly to AI assistants and agent orchestrators. This opens up powerful automation possibilities — AI tools can discover what your endpoints do and call them on your behalf, without any manual wiring. Configuration is managed through a dedicated section in AireGlu, and access is controlled per tenant.</p></div><h4 id="tenant-wide-client-credential-connections-for-http-requests-glu-2998" tabindex="-1">Tenant-Wide Client Credential Connections for HTTP Requests (GLU-2998) <a class="header-anchor" href="#tenant-wide-client-credential-connections-for-http-requests-glu-2998" aria-label="Permalink to “Tenant-Wide Client Credential Connections for HTTP Requests (GLU-2998)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new &quot;Clients&quot; section allows tenant administrators to configure OAuth 2.0 client credential connections that can be selected and reused across HTTP Request tasks in endpoints. These connections support environment variables and secrets in their configuration, automatically refresh tokens on 401 responses, and surface token retrieval failures in usage data logs.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Instead of configuring authentication credentials on each endpoint individually, you can now define a shared client connection once and use it across multiple endpoints. This makes it easier to manage credentials centrally, keep secrets out of endpoint definitions, and troubleshoot authentication failures through the metrics view. For tenants wishing to use this new feature will need to add new permissions if they want to use it (edit:Connection, list:Connection etc.).</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="unsaved-changes-warning-in-endpoint-editor-glu-2813" tabindex="-1">Unsaved Changes Warning in Endpoint Editor (GLU-2813) <a class="header-anchor" href="#unsaved-changes-warning-in-endpoint-editor-glu-2813" aria-label="Permalink to “Unsaved Changes Warning in Endpoint Editor (GLU-2813)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The endpoint editor now displays a warning prompt when you attempt to navigate away with unsaved changes. The alert appears when the endpoint is in edit mode and has pending changes, and does not trigger when closing the browser tab or when there are no unsaved modifications.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll no longer accidentally lose your work when clicking away from the endpoint editor. A clear prompt will ask you to confirm before leaving, giving you the chance to save or discard your changes.</p></div><h4 id="removed-minimum-items-from-auto-generated-schemas-glu-2945" tabindex="-1">Removed Minimum Items from Auto-Generated Schemas (GLU-2945) <a class="header-anchor" href="#removed-minimum-items-from-auto-generated-schemas-glu-2945" aria-label="Permalink to “Removed Minimum Items from Auto-Generated Schemas (GLU-2945)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When generating a JSON schema from example input, AireGlu previously set <code>minItems: 1</code> on arrays, which could cause validation failures for arrays that are legitimately empty at runtime. Auto-generated schemas no longer include a minimum items constraint on array types.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Schemas generated automatically from your example data will be more permissive and less likely to cause unexpected validation errors in production, particularly when working with responses that may contain empty arrays.</p></div><h4 id="retry-support-for-internal-aireglu-endpoint-calls-glu-2967" tabindex="-1">Retry Support for Internal AireGlu Endpoint Calls (GLU-2967) <a class="header-anchor" href="#retry-support-for-internal-aireglu-endpoint-calls-glu-2967" aria-label="Permalink to “Retry Support for Internal AireGlu Endpoint Calls (GLU-2967)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Retry behaviour in the AireGlu Request Task has been extended to cover calls from one AireGlu endpoint to another. This is disabled by default and can be enabled per task. Retries apply only to 5XX server errors, with documentation and in-app messaging updated accordingly.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If your endpoints call other AireGlu endpoints internally, you can now configure those calls to automatically retry on server errors — improving resilience without needing to build custom error-handling logic.</p></div><h4 id="metrics-table-refresh-button-glu-2915" tabindex="-1">Metrics Table Refresh Button (GLU-2915) <a class="header-anchor" href="#metrics-table-refresh-button-glu-2915" aria-label="Permalink to “Metrics Table Refresh Button (GLU-2915)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A refresh button has been added to the usage data metrics table, consistent with the refresh control available on the endpoints list. It is visually distinct from the existing filter reset button to avoid confusion.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now refresh the metrics table on demand without reloading the whole page, making it quicker to check the latest usage data while you&#39;re working.</p></div><h4 id="retry-visibility-in-metrics-glu-3007" tabindex="-1">Retry Visibility in Metrics (GLU-3007) <a class="header-anchor" href="#retry-visibility-in-metrics-glu-3007" aria-label="Permalink to “Retry Visibility in Metrics (GLU-3007)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When AireGlu retries a request, this is now surfaced explicitly in the metrics view. Previously, retries were only identifiable by the presence of multiple invocations for the same endpoint, with no clear indication that a retry had occurred.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Retries are now clearly visible in your usage data, making it easier to identify when an endpoint is experiencing intermittent failures and understand the pattern of retry behaviour.</p></div><h4 id="narrowed-retry-conditions-to-specific-http-exceptions-glu-3024" tabindex="-1">Narrowed Retry Conditions to Specific HTTP Exceptions (GLU-3024) <a class="header-anchor" href="#narrowed-retry-conditions-to-specific-http-exceptions-glu-3024" aria-label="Permalink to “Narrowed Retry Conditions to Specific HTTP Exceptions (GLU-3024)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The resilience retry pipeline has been updated to handle only specific HTTP-related exceptions, following Microsoft&#39;s recommended configuration, rather than catching all exceptions indiscriminately. This reduces the risk of retrying on errors that are not transient or recoverable.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Retries will now behave more predictably and only trigger in situations where they are genuinely likely to help, avoiding unnecessary repeated calls for non-transient errors.</p></div><h4 id="ai-tools-features-now-opt-in-per-tenant-glu-3087" tabindex="-1">AI Tools Features Now Opt-In per Tenant (GLU-3087) <a class="header-anchor" href="#ai-tools-features-now-opt-in-per-tenant-glu-3087" aria-label="Permalink to “AI Tools Features Now Opt-In per Tenant (GLU-3087)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Tenants wishing to use these new AI features should contact Airelogic support</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>AI features will only be available to tenants that have been specifically configured for access, giving organisations greater control over which capabilities are exposed in their environment.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="reactivated-jobs-no-longer-run-immediately-glu-2955" tabindex="-1">Reactivated Jobs No Longer Run Immediately (GLU-2955) <a class="header-anchor" href="#reactivated-jobs-no-longer-run-immediately-glu-2955" aria-label="Permalink to “Reactivated Jobs No Longer Run Immediately (GLU-2955)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When a scheduled job that had previously run was deactivated and then reactivated, it would incorrectly trigger an immediate execution. Jobs are now set to wait for their next scheduled time when reactivated, consistent with the expected scheduling behaviour.</p></div><h4 id="json-editor-overflow-fixed-on-jwt-headers-glu-2900" tabindex="-1">JSON Editor Overflow Fixed on JWT Headers (GLU-2900) <a class="header-anchor" href="#json-editor-overflow-fixed-on-jwt-headers-glu-2900" aria-label="Permalink to “JSON Editor Overflow Fixed on JWT Headers (GLU-2900)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The JSON editor used for configuring JWT headers in the endpoint editor was overflowing its container. The editor now renders correctly within its allocated space.</p></div><h4 id="config-assistant-error-fixed-following-bff-migration-glu-2996" tabindex="-1">Config Assistant Error Fixed Following BFF Migration (GLU-2996) <a class="header-anchor" href="#config-assistant-error-fixed-following-bff-migration-glu-2996" aria-label="Permalink to “Config Assistant Error Fixed Following BFF Migration (GLU-2996)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The AI config assistant in the endpoint editor was returning a 401 authentication error following the BFF (Backend for Frontend) migration. Authentication on the internal request path has been corrected and the assistant is now functional again.</p></div><h4 id="improved-error-message-for-empty-xml-schema-on-save-glu-3036" tabindex="-1">Improved Error Message for Empty XML Schema on Save (GLU-3036) <a class="header-anchor" href="#improved-error-message-for-empty-xml-schema-on-save-glu-3036" aria-label="Permalink to “Improved Error Message for Empty XML Schema on Save (GLU-3036)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Attempting to save an endpoint with an empty or invalid XML schema previously resulted in a silent failure — the UI appeared to save successfully but changes were not persisted. The error handling has been made consistent with the create flow, and a clear error message is now shown to the user.</p></div><h4 id="search-no-longer-opens-all-groups-when-cleared-glu-3016" tabindex="-1">Search No Longer Opens All Groups When Cleared (GLU-3016) <a class="header-anchor" href="#search-no-longer-opens-all-groups-when-cleared-glu-3016" aria-label="Permalink to “Search No Longer Opens All Groups When Cleared (GLU-3016)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Clearing the search bar on the endpoints list was causing all endpoint groups to expand, regardless of their previous state. Groups now correctly return to a closed state when a search is cleared.</p></div><h4 id="pdf-generation-sanitises-user-html-glu-3066" tabindex="-1">PDF Generation Sanitises User HTML (GLU-3066) <a class="header-anchor" href="#pdf-generation-sanitises-user-html-glu-3066" aria-label="Permalink to “PDF Generation Sanitises User HTML (GLU-3066)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>PDF generation now sanitises user-supplied HTML input to prevent local file inclusion attacks via embedded iframes, forms, and unsafe URI schemes. This addresses a high-severity finding from the 2026 penetration test.</p></div><h4 id="graphql-alias-overloading-now-rejected-glu-3075" tabindex="-1">GraphQL Alias Overloading Now Rejected (GLU-3075) <a class="header-anchor" href="#graphql-alias-overloading-now-rejected-glu-3075" aria-label="Permalink to “GraphQL Alias Overloading Now Rejected (GLU-3075)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>GraphQL requests that exceed the permitted alias count are now rejected at the gateway level, preventing alias overloading attacks. This addresses a high-severity finding from the 2026 penetration test.</p></div><h4 id="graphql-nitro-ui-hidden-in-production-glu-2994" tabindex="-1">GraphQL Nitro UI Hidden in Production (GLU-2994) <a class="header-anchor" href="#graphql-nitro-ui-hidden-in-production-glu-2994" aria-label="Permalink to “GraphQL Nitro UI Hidden in Production (GLU-2994)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The GraphQL Nitro browser UI was previously accessible in production environments. It is now restricted to non-production deployments only, reducing the attack surface of the API layer.</p></div><h4 id="xslt-service-dependencies-upgraded-glu-3064" tabindex="-1">XSLT Service Dependencies Upgraded (GLU-3064) <a class="header-anchor" href="#xslt-service-dependencies-upgraded-glu-3064" aria-label="Permalink to “XSLT Service Dependencies Upgraded (GLU-3064)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The XSLT service has had its underlying JDK, Javalin, and Jetty versions upgraded to address known vulnerabilities identified in the 2026 penetration test, including an out-of-date and vulnerable OpenJDK version.</p></div>',69)])])}const g=t(s,[["render",r]]);export{m as __pageData,g as default};
